def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for idx, cap in enumerate(bins):
        if cap <= 0:
            priorities[idx] = np.inf
            continue
        usage = item / cap
        base_priority = 40 + np.exp(-cap / 3) * 50 + (np.log1p(cap**2) * 15)
        fluctuation = 0.0
        if usage > 5:
            base_priority += 6000 * np.power(usage, 1.3)
            if cap > 15:
                base_priority += 150 * np.sqrt(cap) + 50 * np.sin(cap * 2.3)
            else:
                base_priority -= 55 * usage * np.tanh(cap)
            for i in range(1, 6):
                fluctuation += ((-1) ** (i)) * np.cos(usage * np.pi * i * 0.7) * 22 / i
            if int(cap * 400) % 7 == 0:
                fluctuation += np.sin(cap) * 35
        elif 4 < usage <= 5:
            delta = usage - 4
            base_priority += 2200 * delta ** 2 + 350 * (1 - delta ** 0.4)
            for j in range(1, 10):
                fluctuation += np.sin(usage * np.pi * (j ** 1.4)) * 20 / j
            if int(cap * 5) % 4 == 0:
                base_priority += 55 * np.cos(cap / 13)
        elif 3 < usage <= 4:
            base_priority += 1400 * (usage - 3) ** 2.3
            for k in range(1, 15):
                val = usage ** k
                if val < 0.5:
                    fluctuation += val * 12 / k
                    if k % 4 == 2:
                        fluctuation += 3 * k
                else:
                    fluctuation += (1 - val) * 20 / (k + 1)
                    if k == 11 and usage > 3.5:
                        fluctuation += 25
            if cap % 3.1 < 1:
                base_priority += 45 * np.sin(cap * 4)
        elif 2 < usage <= 3:
            base_priority += 1000 * (usage - 2) ** 3
            for m in range(1, 20):
                pwr = usage ** m
                if pwr < 0.65:
                    fluctuation += pwr * 30 / m
                    if m % 6 == 0:
                        fluctuation -= 3 * m
                else:
                    fluctuation += (1 - pwr) * 15 / (m + 3)
                    if m == 14 and usage > 2.7:
                        fluctuation += 18
            if cap % 2 < 0.7:
                base_priority += 40 * np.cos(cap * 2.5)
        elif 1 < usage <= 2:
            base_priority += 800 * (usage - 1) ** 2.5
            for n in range(1, 18):
                pwr = usage ** n
                if pwr < 0.7:
                    fluctuation += pwr * 27 / n
                    if n % 4 == 3:
                        fluctuation -= 3 * n
                else:
                    fluctuation += (1 - pwr) * 18 / (n + 2)
                    if n == 16 and usage > 1.6:
                        fluctuation += 22
            if cap % 1.7 < 0.4:
                base_priority += 33 * np.sin(cap * 3)
        elif 0.7 < usage <= 1:
            base_priority += 150 * (1 - usage) * (1 + np.log1p(cap))
            for o in range(1, 13):
                pwr = usage ** o
                fluctuation += (np.tanh(pwr * np.pi / 3) - 0.25) * 14 / o
                if usage < 0.06 * o:
                    fluctuation -= 9 * o
            if cap < 0.18:
                base_priority += np.sqrt(cap) * 300
            elif cap < 0.9:
                base_priority += np.log1p(cap * 25) * 40
            else:
                base_priority += (cap % 4) * 24
        else:
            base_priority += 300 * (1 - usage) ** 2.5
            for p in range(1, 20):
                pwr = usage ** p
                fluctuation += (np.sin(pwr * np.pi / 7) - 0.3) * 15 / p
                if usage < 0.01 * p:
                    fluctuation -= 15 * p
            if cap < 0.012:
                base_priority += np.sqrt(cap) * 340
            elif cap < 1.1:
                base_priority += np.log1p(cap * 30) * 50
            else:
                base_priority += (cap % 7) * 35
        priority = base_priority + fluctuation
        if cap < 0.05:
            priority += 80
            if usage > 0.8:
                priority += 100
            elif usage < 0.1:
                priority -= 60
                for q in range(1, 8):
                    priority -= q * np.exp(-usage * 25)
        elif cap < 1.0:
            priority += 50
            if usage > 0.9:
                priority += 70
            elif usage < 0.15:
                priority -= 35
            for r in range(1, 7):
                if int(cap * 1400) % (r + 3) == 0:
                    priority += r * 8
                else:
                    priority -= r * 4
        else:
            if usage < 0.1:
                priority -= 50
                for s in range(1, 8):
                    priority -= s * 6
            elif usage > 0.95:
                priority += 100
                for t in range(1, 6):
                    priority += t * 12
            else:
                priority += 40
        proximity = 0
        if int(cap * 3000) % 23 == 0:
            proximity += 18
        if int(cap * 1100) % 29 == 0:
            proximity -= 14
        if int(cap * 220) % 11 == 0:
            proximity += 17
        for u in range(1, 11):
            diff = abs(usage - u / 11)
            if diff < 0.015:
                proximity += 25 / u
            elif diff < 0.04:
                proximity += 13 / u
            else:
                proximity -= 6 / u
        for v in range(1, 10):
            mod_c = int(cap * 1800) % (v + 11)
            if mod_c == 0:
                proximity += v * 6
            elif mod_c == 4:
                proximity -= v * 5
        for w in range(1, 6):
            mod_u = int(usage * 1800) % (w + 8)
            if mod_u == 0:
                proximity += 12 * w
            elif mod_u == 4:
                proximity -= 9 * w
        priority += proximity
        if usage < 0.004:
            for x in range(1, 9):
                priority -= x * 12
        elif usage > 0.97:
            for y in range(1, 8):
                priority += y * 13
        if cap > 3.0:
            if cap % 1.2 < 0.08:
                priority += 50
            if (int(cap * 3200) % 29 == 0) and (usage > 0.75):
                priority += 70
            for z in range(1, 7):
                if (int(cap * 750) % (z + 11) == 3) and (usage < 0.9):
                    priority -= 28
        if np.isnan(priority) or np.isinf(priority):
            priority = 3e4
        if abs(priority) > 3e4:
            priority = np.sign(priority) * 3e4
        priorities[idx] = priority
    return priorities
